<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>PDF Extractor Manual Check</title>
    <style>
      body { font-family: ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, Helvetica, Arial, sans-serif; margin: 24px; }
      .row { display: flex; gap: 12px; align-items: center; flex-wrap: wrap; }
      pre { background: #111; color: #eee; padding: 12px; border-radius: 8px; overflow: auto; max-height: 70vh; }
      button { padding: 8px 12px; }
      input[type=file] { padding: 6px; }
      .muted { color: #666; }
    </style>
  </head>
  <body>
    <h1>PDF Extractor Manual Check</h1>
    <div class="row">
      <input id="file" type="file" accept="application/pdf" />
      <button id="go">Upload & Extract</button>
      <span id="status" class="muted"></span>
    </div>

    <h3>Response JSON</h3>
    <pre id="out">(waiting)</pre>

    <script>
      const $file = document.getElementById('file');
      const $go = document.getElementById('go');
      const $out = document.getElementById('out');
      const $status = document.getElementById('status');

      function setStatus(msg) { $status.textContent = msg; }

      $go.addEventListener('click', async () => {
        if (!$file.files || !$file.files[0]) {
          alert('Pick a PDF first');
          return;
        }
        const f = $file.files[0];
        const form = new FormData();
        form.append('file', f, f.name);

        $out.textContent = '';
        setStatus('Uploading...');
        try {
          const res = await fetch('/extract', { method: 'POST', body: form });
          const text = await res.text();
          let obj;
          try { obj = JSON.parse(text); } catch (e) { obj = { raw: text }; }
          $out.textContent = JSON.stringify(obj, null, 2);
          setStatus(`Done (HTTP ${res.status})`);
        } catch (err) {
          $out.textContent = String(err);
          setStatus('Request failed');
        }
      });
    </script>
  </body>
</html>
HTML
